## 5. 技术方案详解

### 5.1 方案一：修复 WebSocket Store（P0-1）

#### 架构设计

```typescript
// 新的 WebSocket Store 架构
export const useWebSocketStore = defineStore('websocket', () => {
  // ✅ 直接使用 ref 创建响应式状态
  const isConnected = ref(false)
  const isConnecting = ref(false)
  const reconnectAttempts = ref(0)
  const connectionState = ref<ConnectionState>('disconnected')
  const lastError = ref<string | null>(null)

  // WebSocket 实例
  const socket = ref<WebSocket | null>(null)

  // 连接方法
  async function connect() {
    if (isConnected.value || isConnecting.value) {
      return
    }

    isConnecting.value = true
    connectionState.value = 'connecting'

    // 创建 WebSocket 连接
    socket.value = new WebSocket('ws://localhost:3000/api/ws')

    socket.value.onopen = () => {
      isConnected.value = true
      isConnecting.value = false
      connectionState.value = 'connected'
      reconnectAttempts.value = 0
      lastError.value = null
    }

    socket.value.onclose = () => {
      isConnected.value = false
      isConnecting.value = false
      connectionState.value = 'disconnected'

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        const delay = reconnectDelay * Math.pow(2, reconnectAttempts.value)
        setTimeout(() => {
          reconnectAttempts.value++
          connect()
        }, delay)
      } else {
        connectionState.value = 'error'
        lastError.value = '无法连接到服务器'
      }
    }

    socket.value.onmessage = (event) => {
      const { event: eventType, data } = JSON.parse(event.data)
      handleMessage(eventType, data)
    }
  }

  // 消息分发
  function handleMessage(event: string, data: any) {
    switch (event) {
      case 'iteration.status_changed':
        useIterationStore().updateIteration(data)
        break
      case 'agent.status_changed':
        useAgentStore().updateAgent(data)
        break
      case 'system.metrics':
        useOverviewStore().updateMetrics(data)
        break
    }
  }

  return {
    isConnected,
    isConnecting,
    reconnectAttempts,
    connectionState,
    lastError,
    connect,
    disconnect,
    send
  }
})
```

