### 5.2 方案二：AutoIterationEngine 集成 Dashboard（P0-2）

#### 集成架构

```typescript
// 修改 AutoIterationEngine 类
export class AutoIterationEngine {
  // ✅ 新增: Dashboard 服务引用
  private realtimeService: RealtimeService | null = null
  private iterationService: IterationService | null = null
  private currentIterationId: string | null = null

  async start(): Promise<void> {
    if (this.isRunning) {
      console.log('⚠️  自动迭代已在运行中')
      return
    }

    this.isRunning = true

    // ✅ 新增: 初始化 Dashboard 服务
    try {
      const services = getServices()
      this.realtimeService = services.realtimeService
      this.iterationService = services.iterationService
      console.log('✅ Dashboard 服务已连接')
    } catch (error) {
      console.log('⚠️  Dashboard 服务未启动,将独立运行')
    }

    this.runIterationLoop()
  }

  async runIteration(): Promise<void> {
    console.log(`\n🔄 迭代 #${this.iterationCount}`)

    // ✅ 创建迭代记录
    let iterationRecord = null
    if (this.iterationService) {
      try {
        iterationRecord = await this.iterationService.create({
          iterationNumber: this.iterationCount,
          status: 'running',
          requirement: '自动发现的需求',
          createdAt: new Date()
        })

        this.currentIterationId = iterationRecord.id

        // 推送迭代状态
        await this.realtimeService?.broadcastIterationStatusChange({
          iterationId: iterationRecord.id,
          iterationNumber: this.iterationCount,
          status: 'running',
          progress: 0
        })
      } catch (error) {
        console.error('❌ 创建迭代记录失败:', error)
      }
    }

    // === 阶段 1: 产品经理 ===
    console.log('\n📊 阶段 1/4: 产品经理分析需求...')

    // 推送进度
    if (this.realtimeService) {
      await this.realtimeService.broadcastIterationProgress({
        iterationId: this.currentIterationId || '',
        progress: 10,
        phase: 'product_manager',
        message: '产品经理正在分析项目...'
      })
    }

    const pmResult = await this.productManager.execute(this.config.projectPath)

    // 推送 Agent 状态
    if (this.realtimeService) {
      await this.realtimeService.broadcastAgentStatusChange({
        agentName: 'product-manager',
        status: 'running',
        task: '分析项目需求...',
        iterationId: this.currentIterationId || '',
        progress: 50
      })
    }

    // === 其他阶段类似 ===

    // === 完成 ===
    console.log('\n✅ 迭代完成')

    if (this.iterationService && iterationRecord) {
      await this.iterationService.update(iterationRecord.id, {
        status: 'success',
        progress: 100,
        completedAt: new Date()
      })

      // 推送完成事件
      if (this.realtimeService) {
        await this.realtimeService.broadcastIterationStatusChange({
          iterationId: iterationRecord.id,
          status: 'success',
          progress: 100
        })
      }
    }

    this.iterationCount++
  }
}
```

