### 5.4 方案四：完善 Store 数据同步（P0-5）

#### Iteration Store 增强

```typescript
export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<Iteration | null>(null)
  const loading = ref(false)
  const error = ref<string | null>(null)

  // ✅ 新增: WebSocket 更新方法
  function updateIteration(iteration: Iteration) {
    const index = iterations.value.findIndex(i => i.id === iteration.id)
    if (index !== -1) {
      iterations.value[index] = iteration
    } else {
      iterations.value.unshift(iteration)
    }

    if (currentIteration.value?.id === iteration.id) {
      currentIteration.value = iteration
    }
  }

  function updateProgress(id: string, progress: number) {
    const iteration = iterations.value.find(i => i.id === id)
    if (iteration) {
      iteration.progress = progress
    }

    if (currentIteration.value?.id === id) {
      currentIteration.value.progress = progress
    }
  }

  function updateStatus(id: string, status: Iteration['status']) {
    const iteration = iterations.value.find(i => i.id === id)
    if (iteration) {
      iteration.status = status
    }

    if (currentIteration.value?.id === id) {
      currentIteration.value.status = status
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    error,
    fetchIterations,
    fetchCurrentIteration,
    updateIteration,
    updateProgress,
    updateStatus
  }
})
```

#### Agent Store 增强

```typescript
export const useAgentStore = defineStore('agent', () => {
  const agents = ref<Agent[]>([])
  const loading = ref(false)
  const error = ref<string | null>(null)

  // ✅ 新增: WebSocket 更新方法
  function updateAgent(data: AgentStatusChange) {
    const { agentName, status, task, iterationId, progress } = data
    const agent = agents.value.find(a => a.name === agentName)

    if (agent) {
      agent.status = status
      agent.currentTask = task
      agent.iterationId = iterationId
      if (progress !== undefined) {
        agent.progress = progress
      }

      if (status === 'running') {
        agent.totalExecutions++
      }
    } else {
      agents.value.push({
        name: agentName,
        displayName: getDisplayName(agentName),
        status,
        currentTask: task,
        iterationId,
        progress: progress || 0,
        totalExecutions: status === 'running' ? 1 : 0,
        successRate: 100.0,
        icon: getIcon(agentName)
      })
    }
  }

  function updateAgentProgress(agentName: string, progress: number) {
    const agent = agents.value.find(a => a.name === agentName)
    if (agent) {
      agent.progress = progress
    }
  }

  return {
    agents,
    loading,
    error,
    fetchAgents,
    fetchAgentStats,
    updateAgent,
    updateAgentProgress
  }
})
```

